import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useTheme } from '../../context/ThemeContext';
import './Header.css';

function NavItem({ to, children, location }) {
  // Exact match — '/' only matches home, not /about
  const active = to === '/' 
    ? location.pathname === '/' 
    : location.pathname === to || location.pathname.startsWith(to);

  return (
    <Link to={to} className="header__link" data-active={active ? 'true' : 'false'}>
      {children}
      {/* Underline — only shown when active OR on hover via CSS */}
      <span className={`nav-underline ${active ? 'nav-underline--active' : ''}`} />
    </Link>
  );
}

export default function Header() {
  const { user, logout } = useAuth();
  const { isDark, toggleTheme } = useTheme();
  const location = useLocation();
  const navigate = useNavigate();
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [toggling, setToggling] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => { setMenuOpen(false); }, [location]);

  const handleLogout = () => { logout(); navigate('/'); };
  const isHome = location.pathname === '/';

  const handleToggle = () => {
    setToggling(true);
    setTimeout(() => setToggling(false), 600);
    toggleTheme();
  };

  return (
    <header className={`header ${scrolled || !isHome ? 'header--solid' : ''}`}>
      <div className="header__inner container">

        <Link to="/" className="header__logo">
          <span className="header__logo-icon">✦</span>
          <span className="header__logo-text">LUXE LIBRARY</span>
        </Link>

        <nav className={`header__nav ${menuOpen ? 'header__nav--open' : ''}`}>
          <NavItem to="/" location={location}>Home</NavItem>
          <a href="/#collection" className="header__link">
            Collection
            <span className="nav-underline" />
          </a>
          <NavItem to="/about" location={location}>About</NavItem>
          <NavItem to="/contact" location={location}>Contact</NavItem>
          {user && (
            <NavItem
              to={user.role === 'admin' ? '/admin' : '/dashboard'}
              location={location}
            >
              {user.role === 'admin' ? 'Admin Panel' : 'My Dashboard'}
            </NavItem>
          )}
        </nav>

        <div className="header__auth">
          <button
            className={`theme-toggle ${isDark ? 'theme-toggle--dark' : 'theme-toggle--light'} ${toggling ? 'theme-toggle--spinning' : ''}`}
            onClick={handleToggle}
            aria-label="Toggle theme"
          >
            <span className="theme-toggle__track">
              <span className="theme-toggle__thumb">
                <span className="theme-toggle__icon">{isDark ? '🌙' : '☀️'}</span>
              </span>
            </span>
            <span className="theme-toggle__label">{isDark ? 'Dark' : 'Light'}</span>
          </button>

          {user ? (
            <div className="header__user">
              <div className="header__avatar">{user.name.charAt(0).toUpperCase()}</div>
              <div className="header__user-info">
                <span className="header__user-name">{user.name}</span>
                <span className="header__user-role">{user.role}</span>
              </div>
              <button className="header__logout" onClick={handleLogout}>Sign Out</button>
            </div>
          ) : (
            <>
              <Link to="/login" className="header__btn-ghost">Sign In</Link>
              <Link to="/signup" className="header__btn-gold">Join Now</Link>
            </>
          )}
        </div>

        <button className={`header__hamburger ${menuOpen ? 'open' : ''}`} onClick={() => setMenuOpen(!menuOpen)}>
          <span /><span /><span />
        </button>
      </div>
    </header>
  );
}
